// ─── Score categories ────────────────────────────────────────────────────────
const SCORE_CATS = [
  { key: "professionalism", label: "Professionalism", icon: "🎩" },
  { key: "clarity",         label: "Clarity",         icon: "💡" },
  { key: "tone",            label: "Tone",             icon: "🤝" },
  { key: "grammar",         label: "Grammar",          icon: "✏️" },
  { key: "effectiveness",   label: "Effectiveness",    icon: "🎯" },
];

// ─── Helpers ─────────────────────────────────────────────────────────────────
function gradeFromScore(score) {
  if (score >= 90) return { letter: "A", color: B.green,  bg: B.greenL };
  if (score >= 80) return { letter: "B", color: "#1D6FA4", bg: "#E8F3FB" };
  if (score >= 70) return { letter: "C", color: B.amber,  bg: B.amberL };
  if (score >= 60) return { letter: "D", color: "#9B4B00", bg: "#FEE9D4" };
  return             { letter: "F", color: B.red,   bg: B.redL  };
}

function tagColor(tag) {
  const m = { Billing: "#6B48C8", "Vehicle Update": "#0E7A6E", Documents: "#1D6FA4", Endorsement: "#8B6914", "Policy Change": "#2D7A3E", Cancellation: B.lava };
  return m[tag] || B.slateM;
}

function diffColor(d) {
  return d === "Beginner" ? B.green : d === "Intermediate" ? B.amber : B.red;
}

// ─── Sub-components ──────────────────────────────────────────────────────────
function ScoreMeter({ value, max = 100 }) {
  const pct = Math.round((value / max) * 100);
  const g = gradeFromScore(value);
  return (
    <div style={{ width: "100%" }}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
        <span style={{ fontFamily: font.body, fontSize: 12, color: B.slateL }}>{value}/{max}</span>
        <span style={{ fontFamily: font.body, fontSize: 12, fontWeight: 600, color: g.color }}>{pct}%</span>
      </div>
      <div style={{ height: 8, borderRadius: 4, background: B.ashD, overflow: "hidden" }}>
        <div style={{ height: "100%", width: `${pct}%`, background: g.color, borderRadius: 4, transition: "width 0.8s ease" }} />
      </div>
    </div>
  );
}

function Badge({ label, color, bg }) {
  return (
    <span style={{ display: "inline-block", padding: "2px 10px", borderRadius: 20, background: bg || "#eee", color: color || B.slateM, fontFamily: font.body, fontSize: 11, fontWeight: 600, letterSpacing: "0.03em" }}>
      {label}
    </span>
  );
}

// ─── Main App ────────────────────────────────────────────────────────────────
export default function InsuranceEmailTrainer() {
  const [view, setView]           = useState("home");      // home | scenario | result | history
  const [scenario, setScenario]   = useState(null);
  const [email, setEmail]         = useState("");
  const [loading, setLoading]     = useState(false);
  const [result, setResult]       = useState(null);
  const [history, setHistory]     = useState([]);
  const [filterTag, setFilterTag] = useState("All");
  const [filterDiff, setFilterDiff] = useState("All");
  const textRef = useRef(null);

  const allTags  = ["All", ...new Set(SCENARIOS.map(s => s.tag))];
  const allDiffs = ["All", "Beginner", "Intermediate", "Advanced"];

  const filtered = SCENARIOS.filter(s =>
    (filterTag  === "All" || s.tag        === filterTag)  &&
    (filterDiff === "All" || s.difficulty === filterDiff)
  );

  function openScenario(s) {
    setScenario(s);
    setEmail("");
    setResult(null);
    setView("scenario");
    setTimeout(() => textRef.current?.focus(), 100);
  }

  async function submitEmail() {
    if (email.trim().length < 50) return;
    setLoading(true);
    try {
      const prompt = `You are a senior insurance customer service quality evaluator.

A CSR has written the following email response to a customer scenario. Evaluate it on five dimensions, each scored 0–20 (total out of 100).

--- SCENARIO ---
${scenario.title}

Customer email:
${scenario.body}

Context for the CSR (not visible to customer):
${scenario.context}

Tips to evaluate against:
${scenario.tips.map((t, i) => `${i + 1}. ${t}`).join("\n")}

--- CSR EMAIL RESPONSE ---
${email}
--- END ---

Return ONLY a JSON object with this exact shape — no preamble, no markdown fences:
{
  "professionalism": <0-20>,
  "clarity": <0-20>,
  "tone": <0-20>,
  "grammar": <0-20>,
  "effectiveness": <0-20>,
  "overall_comment": "<2-3 sentence overall assessment>",
  "strengths": ["<strength 1>", "<strength 2>"],
  "improvements": ["<improvement 1>", "<improvement 2>", "<improvement 3>"],
  "sample_line": "<one exemplary sentence the CSR could use or did use well>"
}`;

      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-6",
          max_tokens: 1000,
          messages: [{ role: "user", content: prompt }],
        }),
      });
      const data = await res.json();
      const raw  = data.content?.find(b => b.type === "text")?.text || "{}";
      const clean = raw.replace(/```json|```/g, "").trim();
      const scores = JSON.parse(clean);
      const total  = scores.professionalism + scores.clarity + scores.tone + scores.grammar + scores.effectiveness;
      const entry  = { id: Date.now(), scenarioId: scenario.id, scenarioTitle: scenario.title, tag: scenario.tag, email, scores, total, timestamp: new Date().toLocaleString() };
      setResult(entry);
      setHistory(prev => [entry, ...prev]);
      setView("result");
    } catch (err) {
      console.error(err);
      alert("Scoring failed. Please try again.");
    } finally {
      setLoading(false);
    }
  }

  // ── VIEWS ──────────────────────────────────────────────────────────────────

  // HOME
  if (view === "home") return (
    <div style={{ minHeight: "100vh", background: B.ash, fontFamily: font.body }}>
      {/* Header */}
      <div style={{ background: B.slate, padding: "0 32px" }}>
        <div style={{ maxWidth: 1100, margin: "0 auto", display: "flex", alignItems: "center", justifyContent: "space-between", height: 64 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
            <img src={LAVA_LOGO} alt="Lava" style={{ width: 32, height: 32, borderRadius: 6, display: "block" }} />
            <span style={{ fontFamily: font.display, fontSize: 14, fontWeight: 700, color: B.white, letterSpacing: "0.1em", textTransform: "uppercase" }}>LAVA Training</span>
            <span style={{ color: B.slateL, fontSize: 12, marginLeft: 4 }}>/ Email Trainer</span>
          </div>
          <button onClick={() => setView("history")}
            style={{ background: "transparent", border: `1px solid ${B.slateM}`, color: B.slateL, borderRadius: 6, padding: "6px 16px", fontFamily: font.body, fontSize: 12, cursor: "pointer" }}>
            My History ({history.length})
          </button>
        </div>
      </div>

      {/* Hero */}
      <div style={{ background: B.slate, padding: "48px 32px 56px" }}>
        <div style={{ maxWidth: 1100, margin: "0 auto" }}>
          <div style={{ display: "inline-block", background: B.lava, color: B.white, borderRadius: 4, padding: "4px 12px", fontSize: 11, fontWeight: 700, letterSpacing: "0.12em", textTransform: "uppercase", marginBottom: 16 }}>
            CSR Training · Insurance
          </div>
          <h1 style={{ fontFamily: font.display, fontSize: "clamp(28px, 4vw, 48px)", fontWeight: 800, color: B.white, margin: "0 0 12px", letterSpacing: "-0.01em", lineHeight: 1.1 }}>
            EMAIL RESPONSE<br />
            <span style={{ color: B.lava }}>SIMULATOR</span>
          </h1>
          <p style={{ color: B.slateL, fontSize: 15, maxWidth: 560, lineHeight: 1.7, margin: 0 }}>
            Read real customer scenarios, write your best email from scratch, and get instant AI-powered scores on professionalism, clarity, tone, grammar, and effectiveness.
          </p>
          <div style={{ display: "flex", gap: 24, marginTop: 32, flexWrap: "wrap" }}>
            {[["📋", `${SCENARIOS.length}`, "Scenarios"], ["🏆", "5", "Scoring Dimensions"], ["⚡", "AI", "Instant Feedback"]].map(([icon, val, lbl]) => (
              <div key={lbl} style={{ background: "rgba(255,255,255,0.06)", borderRadius: 10, padding: "16px 24px", textAlign: "center", minWidth: 80 }}>
                <div style={{ fontSize: 22, marginBottom: 4 }}>{icon}</div>
                <div style={{ fontFamily: font.display, fontSize: 22, color: B.white, fontWeight: 800 }}>{val}</div>
                <div style={{ fontSize: 11, color: B.slateL, textTransform: "uppercase", letterSpacing: "0.08em" }}>{lbl}</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Filters + Cards */}
      <div style={{ maxWidth: 1100, margin: "0 auto", padding: "40px 32px" }}>
        <div style={{ display: "flex", gap: 32, marginBottom: 28, flexWrap: "wrap", alignItems: "center" }}>
          <div>
            <span style={{ fontSize: 11, color: B.slateL, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.08em", marginRight: 10 }}>Category</span>
            {allTags.map(t => (
              <button key={t} onClick={() => setFilterTag(t)}
                style={{ marginRight: 6, padding: "4px 12px", borderRadius: 20, border: `1px solid ${filterTag === t ? B.lava : B.ashD}`, background: filterTag === t ? B.lava : B.white, color: filterTag === t ? B.white : B.slateM, fontFamily: font.body, fontSize: 12, cursor: "pointer", fontWeight: filterTag === t ? 600 : 400 }}>
                {t}
              </button>
            ))}
          </div>
          <div>
            <span style={{ fontSize: 11, color: B.slateL, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.08em", marginRight: 10 }}>Level</span>
            {allDiffs.map(d => (
              <button key={d} onClick={() => setFilterDiff(d)}
                style={{ marginRight: 6, padding: "4px 12px", borderRadius: 20, border: `1px solid ${filterDiff === d ? B.slate : B.ashD}`, background: filterDiff === d ? B.slate : B.white, color: filterDiff === d ? B.white : B.slateM, fontFamily: font.body, fontSize: 12, cursor: "pointer", fontWeight: filterDiff === d ? 600 : 400 }}>
                {d}
              </button>
            ))}
          </div>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: 20 }}>
          {filtered.map(s => {
            const attempted = history.find(h => h.scenarioId === s.id);
            const g = attempted ? gradeFromScore(attempted.total) : null;
            return (
              <div key={s.id} onClick={() => openScenario(s)}
                style={{ background: B.white, borderRadius: 12, border: `1px solid ${B.ashD}`, padding: 24, cursor: "pointer", transition: "box-shadow 0.15s, transform 0.15s", position: "relative", overflow: "hidden" }}
                onMouseEnter={e => { e.currentTarget.style.boxShadow = "0 4px 24px rgba(0,0,0,0.10)"; e.currentTarget.style.transform = "translateY(-2px)"; }}
                onMouseLeave={e => { e.currentTarget.style.boxShadow = "none"; e.currentTarget.style.transform = "none"; }}>
                {attempted && (
                  <div style={{ position: "absolute", top: 16, right: 16, width: 36, height: 36, borderRadius: "50%", background: g.bg, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: font.display, fontSize: 16, fontWeight: 800, color: g.color }}>
                    {g.letter}
                  </div>
                )}
                <div style={{ display: "flex", gap: 8, marginBottom: 12, flexWrap: "wrap" }}>
                  <Badge label={s.tag} color={B.white} bg={tagColor(s.tag)} />
                  <Badge label={s.difficulty} color={diffColor(s.difficulty)} bg={`${diffColor(s.difficulty)}18`} />
                </div>
                <div style={{ fontFamily: font.display, fontSize: 15, fontWeight: 700, color: B.slate, lineHeight: 1.3, marginBottom: 8 }}>
                  {s.title}
                </div>
                <p style={{ fontSize: 13, color: B.slateL, lineHeight: 1.6, margin: "0 0 16px", display: "-webkit-box", WebkitLineClamp: 3, WebkitBoxOrient: "vertical", overflow: "hidden" }}>
                  {s.body.split("\n")[0]}
                </p>
                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                  <span style={{ fontSize: 12, color: B.slateL }}>{s.tips.length} evaluation criteria</span>
                  <span style={{ fontSize: 12, fontWeight: 600, color: B.lava }}>Start →</span>
                </div>
              </div>
            );
          })}
        </div>

        {filtered.length === 0 && (
          <div style={{ textAlign: "center", padding: "60px 0", color: B.slateL }}>
            No scenarios match your filters.
          </div>
        )}
      </div>
    </div>
  );

  // SCENARIO / WRITING
  if (view === "scenario" && scenario) {
    const wordCount = email.trim() ? email.trim().split(/\s+/).length : 0;
    const ready = email.trim().length >= 50;
    return (
      <div style={{ minHeight: "100vh", background: B.ash, fontFamily: font.body }}>
        {/* Nav */}
        <div style={{ background: B.slate, padding: "0 32px" }}>
          <div style={{ maxWidth: 1100, margin: "0 auto", display: "flex", alignItems: "center", gap: 16, height: 56 }}>
            <button onClick={() => setView("home")} style={{ background: "transparent", border: "none", color: B.slateL, fontFamily: font.body, fontSize: 13, cursor: "pointer", display: "flex", alignItems: "center", gap: 6 }}>
              ← Back
            </button>
            <div style={{ width: 1, height: 20, background: B.slateM }} />
            <div style={{ display: "flex", gap: 8 }}>
              <Badge label={scenario.tag} color={B.white} bg={tagColor(scenario.tag)} />
              <Badge label={scenario.difficulty} color={diffColor(scenario.difficulty)} bg={`${diffColor(scenario.difficulty)}18`} />
            </div>
          </div>
        </div>

        <div style={{ maxWidth: 1100, margin: "0 auto", padding: "32px 32px", display: "grid", gridTemplateColumns: "1fr 1fr", gap: 28 }}>
          {/* Left — customer email */}
          <div>
            <div style={{ fontFamily: font.display, fontSize: 11, fontWeight: 700, color: B.slateL, letterSpacing: "0.12em", textTransform: "uppercase", marginBottom: 12 }}>
              Customer Email
            </div>
            <div style={{ background: B.white, borderRadius: 12, border: `1px solid ${B.ashD}`, overflow: "hidden" }}>
              {/* Email header chrome */}
              <div style={{ background: B.ash, borderBottom: `1px solid ${B.ashD}`, padding: "14px 20px" }}>
                <div style={{ fontSize: 13, color: B.slateL, marginBottom: 4 }}>
                  <span style={{ color: B.slateM, fontWeight: 500 }}>From: </span>{scenario.from}
                </div>
                <div style={{ fontSize: 13, color: B.slateL, marginBottom: 4 }}>
                  <span style={{ color: B.slateM, fontWeight: 500 }}>Subject: </span>{scenario.subject}
                </div>
                <div style={{ fontSize: 12, color: B.slateL }}>
                  <span style={{ color: B.slateM, fontWeight: 500 }}>Received: </span>{scenario.receivedAt}
                </div>
              </div>
              <div style={{ padding: 24 }}>
                <h2 style={{ fontFamily: font.display, fontSize: 17, fontWeight: 700, color: B.slate, margin: "0 0 16px" }}>
                  {scenario.title}
                </h2>
                <pre style={{ fontFamily: font.body, fontSize: 14, color: B.black, lineHeight: 1.8, whiteSpace: "pre-wrap", margin: 0 }}>
                  {scenario.body}
                </pre>
              </div>
            </div>

            {/* Context */}
            <div style={{ marginTop: 20, background: B.amberL, border: `1px solid #F6D860`, borderRadius: 10, padding: 18 }}>
              <div style={{ fontSize: 11, fontWeight: 700, color: B.amber, textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 8 }}>📋 Your Policy Context</div>
              <p style={{ fontSize: 13, color: "#7A4A00", lineHeight: 1.7, margin: 0 }}>{scenario.context}</p>
            </div>

            {/* Tips */}
            <div style={{ marginTop: 16, background: B.lavaL, border: `1px solid #F5BFB0`, borderRadius: 10, padding: 18 }}>
              <div style={{ fontSize: 11, fontWeight: 700, color: B.lavaD, textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 10 }}>🎯 Evaluation Criteria</div>
              {scenario.tips.map((t, i) => (
                <div key={i} style={{ display: "flex", gap: 10, marginBottom: 8 }}>
                  <span style={{ color: B.lava, fontWeight: 700, fontSize: 13, minWidth: 20 }}>{i + 1}.</span>
                  <span style={{ fontSize: 13, color: B.slateM, lineHeight: 1.6 }}>{t}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Right — writing area */}
          <div>
            <div style={{ fontFamily: font.display, fontSize: 11, fontWeight: 700, color: B.slateL, letterSpacing: "0.12em", textTransform: "uppercase", marginBottom: 12 }}>
              Your Email Response
            </div>
            <div style={{ background: B.white, borderRadius: 12, border: `1px solid ${B.ashD}`, overflow: "hidden", display: "flex", flexDirection: "column" }}>
              {/* Compose chrome */}
              <div style={{ background: B.ash, borderBottom: `1px solid ${B.ashD}`, padding: "12px 20px" }}>
                <div style={{ fontSize: 13, color: B.slateL }}>
                  <span style={{ color: B.slateM, fontWeight: 500 }}>To: </span>{scenario.from}
                </div>
                <div style={{ fontSize: 13, color: B.slateL, marginTop: 4 }}>
                  <span style={{ color: B.slateM, fontWeight: 500 }}>Re: </span>{scenario.subject}
                </div>
              </div>
              <textarea
                ref={textRef}
                value={email}
                onChange={e => setEmail(e.target.value)}
                placeholder={`Write your full email response to ${scenario.from.split(" ")[0]} here...\n\nInclude a proper greeting, address their concerns completely, provide next steps, and close professionally.`}
                style={{ flex: 1, minHeight: 420, padding: 24, fontFamily: font.body, fontSize: 14, lineHeight: 1.8, color: B.black, border: "none", outline: "none", resize: "vertical", background: B.white }}
              />
              <div style={{ borderTop: `1px solid ${B.ashD}`, padding: "12px 20px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                <span style={{ fontSize: 12, color: B.slateL }}>{wordCount} words · {email.length} chars</span>
                <button
                  onClick={submitEmail}
                  disabled={!ready || loading}
                  style={{ background: ready && !loading ? B.lava : B.ashD, color: ready && !loading ? B.white : B.slateL, border: "none", borderRadius: 8, padding: "10px 24px", fontFamily: font.body, fontSize: 14, fontWeight: 600, cursor: ready && !loading ? "pointer" : "not-allowed", transition: "background 0.2s", display: "flex", alignItems: "center", gap: 8 }}>
                  {loading ? (
                    <><span style={{ display: "inline-block", width: 14, height: 14, border: `2px solid ${B.white}`, borderTopColor: "transparent", borderRadius: "50%", animation: "spin 0.7s linear infinite" }} />Scoring...</>
                  ) : "Submit & Score →"}
                </button>
              </div>
            </div>
            {!ready && email.length > 0 && (
              <p style={{ fontSize: 12, color: B.slateL, marginTop: 8 }}>Write at least 50 characters to submit.</p>
            )}
          </div>
        </div>

        <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }

  // RESULT
  if (view === "result" && result) {
    const g = gradeFromScore(result.total);
    return (
      <div style={{ minHeight: "100vh", background: B.ash, fontFamily: font.body }}>
        <div style={{ background: B.slate, padding: "0 32px" }}>
          <div style={{ maxWidth: 1100, margin: "0 auto", display: "flex", alignItems: "center", gap: 16, height: 56 }}>
            <button onClick={() => setView("home")} style={{ background: "transparent", border: "none", color: B.slateL, fontFamily: font.body, fontSize: 13, cursor: "pointer" }}>← All Scenarios</button>
            <div style={{ width: 1, height: 20, background: B.slateM }} />
            <button onClick={() => openScenario(scenario)} style={{ background: "transparent", border: "none", color: B.slateL, fontFamily: font.body, fontSize: 13, cursor: "pointer" }}>Retry this scenario</button>
          </div>
        </div>

        <div style={{ maxWidth: 900, margin: "0 auto", padding: "40px 32px" }}>
          {/* Score hero */}
          <div style={{ background: B.white, borderRadius: 16, border: `1px solid ${B.ashD}`, padding: 36, marginBottom: 24, display: "flex", gap: 32, alignItems: "center", flexWrap: "wrap" }}>
            <div style={{ textAlign: "center", minWidth: 120 }}>
              <div style={{ width: 96, height: 96, borderRadius: "50%", background: g.bg, border: `4px solid ${g.color}`, display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 12px", fontFamily: font.display, fontSize: 42, fontWeight: 800, color: g.color }}>
                {g.letter}
              </div>
              <div style={{ fontFamily: font.display, fontSize: 28, fontWeight: 800, color: B.slate }}>{result.total}</div>
              <div style={{ fontSize: 12, color: B.slateL }}>out of 100</div>
            </div>
            <div style={{ flex: 1, minWidth: 260 }}>
              <div style={{ fontFamily: font.display, fontSize: 13, fontWeight: 700, color: B.slateL, letterSpacing: "0.1em", textTransform: "uppercase", marginBottom: 6 }}>Score Summary</div>
              <div style={{ fontFamily: font.display, fontSize: 20, fontWeight: 700, color: B.slate, marginBottom: 12 }}>{scenario?.title}</div>
              <p style={{ fontSize: 14, color: B.slateM, lineHeight: 1.7, margin: 0 }}>{result.scores.overall_comment}</p>
            </div>
          </div>

          {/* Category scores */}
          <div style={{ background: B.white, borderRadius: 12, border: `1px solid ${B.ashD}`, padding: 28, marginBottom: 24 }}>
            <div style={{ fontFamily: font.display, fontSize: 11, fontWeight: 700, color: B.slateL, letterSpacing: "0.12em", textTransform: "uppercase", marginBottom: 20 }}>Detailed Scores</div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))", gap: 20 }}>
              {SCORE_CATS.map(c => (
                <div key={c.key} style={{ background: B.ash, borderRadius: 8, padding: 16 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}>
                    <span style={{ fontSize: 18 }}>{c.icon}</span>
                    <span style={{ fontSize: 13, fontWeight: 600, color: B.slate }}>{c.label}</span>
                    <span style={{ marginLeft: "auto", fontFamily: font.display, fontSize: 18, fontWeight: 800, color: gradeFromScore(result.scores[c.key] * 5).color }}>
                      {result.scores[c.key]}<span style={{ fontSize: 12, fontWeight: 400, color: B.slateL }}>/20</span>
                    </span>
                  </div>
                  <ScoreMeter value={result.scores[c.key]} max={20} />
                </div>
              ))}
            </div>
          </div>

          {/* Strengths + Improvements */}
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20, marginBottom: 24 }}>
            <div style={{ background: B.greenL, border: `1px solid #A8DFC4`, borderRadius: 12, padding: 24 }}>
              <div style={{ fontSize: 11, fontWeight: 700, color: B.green, textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: 14 }}>✓ What You Did Well</div>
              {result.scores.strengths.map((s, i) => (
                <div key={i} style={{ display: "flex", gap: 10, marginBottom: 10 }}>
                  <span style={{ color: B.green, fontWeight: 700 }}>•</span>
                  <span style={{ fontSize: 13, color: "#1A4A35", lineHeight: 1.6 }}>{s}</span>
                </div>
              ))}
            </div>
            <div style={{ background: B.lavaL, border: `1px solid #F5BFB0`, borderRadius: 12, padding: 24 }}>
              <div style={{ fontSize: 11, fontWeight: 700, color: B.lavaD, textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: 14 }}>→ Areas to Improve</div>
              {result.scores.improvements.map((s, i) => (
                <div key={i} style={{ display: "flex", gap: 10, marginBottom: 10 }}>
                  <span style={{ color: B.lava, fontWeight: 700 }}>•</span>
                  <span style={{ fontSize: 13, color: "#6B1F10", lineHeight: 1.6 }}>{s}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Sample line */}
          {result.scores.sample_line && (
            <div style={{ background: B.slate, borderRadius: 12, padding: 24, marginBottom: 24 }}>
              <div style={{ fontSize: 11, fontWeight: 700, color: B.slateL, textTransform: "uppercase", letterSpacing: "0.1em", marginBottom: 10 }}>💬 Exemplary Line</div>
              <p style={{ fontSize: 15, color: B.white, lineHeight: 1.7, margin: 0, fontStyle: "italic" }}>"{result.scores.sample_line}"</p>
            </div>
          )}

          {/* Your email */}
          <div style={{ background: B.white, borderRadius: 12, border: `1px solid ${B.ashD}`, overflow: "hidden", marginBottom: 24 }}>
            <div style={{ background: B.ash, borderBottom: `1px solid ${B.ashD}`, padding: "12px 20px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
              <span style={{ fontSize: 11, fontWeight: 700, color: B.slateL, textTransform: "uppercase", letterSpacing: "0.1em" }}>Your Submitted Response</span>
            </div>
            <pre style={{ padding: 24, fontFamily: font.body, fontSize: 14, color: B.black, lineHeight: 1.8, whiteSpace: "pre-wrap", margin: 0 }}>
              {result.email}
            </pre>
          </div>

          <div style={{ display: "flex", gap: 12 }}>
            <button onClick={() => openScenario(scenario)} style={{ background: B.lava, color: B.white, border: "none", borderRadius: 8, padding: "12px 28px", fontFamily: font.body, fontSize: 14, fontWeight: 600, cursor: "pointer" }}>
              Try Again
            </button>
            <button onClick={() => setView("home")} style={{ background: B.white, color: B.slate, border: `1px solid ${B.ashD}`, borderRadius: 8, padding: "12px 28px", fontFamily: font.body, fontSize: 14, fontWeight: 600, cursor: "pointer" }}>
              Next Scenario
            </button>
            <button onClick={() => setView("history")} style={{ background: "transparent", color: B.slateM, border: `1px solid ${B.ashD}`, borderRadius: 8, padding: "12px 28px", fontFamily: font.body, fontSize: 14, cursor: "pointer" }}>
              View History
            </button>
          </div>
        </div>
      </div>
    );
  }

  // HISTORY
  if (view === "history") {
    const avg = history.length ? Math.round(history.reduce((s, h) => s + h.total, 0) / history.length) : null;
    return (
      <div style={{ minHeight: "100vh", background: B.ash, fontFamily: font.body }}>
        <div style={{ background: B.slate, padding: "0 32px" }}>
          <div style={{ maxWidth: 1100, margin: "0 auto", display: "flex", alignItems: "center", height: 56 }}>
            <button onClick={() => setView("home")} style={{ background: "transparent", border: "none", color: B.slateL, fontFamily: font.body, fontSize: 13, cursor: "pointer" }}>← Back to Scenarios</button>
          </div>
        </div>
        <div style={{ maxWidth: 900, margin: "0 auto", padding: "40px 32px" }}>
          <div style={{ fontFamily: font.display, fontSize: 28, fontWeight: 800, color: B.slate, marginBottom: 4 }}>MY HISTORY</div>
          {history.length > 0 && (
            <div style={{ display: "flex", gap: 24, marginBottom: 32, flexWrap: "wrap" }}>
              <div style={{ background: B.white, borderRadius: 10, padding: "16px 24px", border: `1px solid ${B.ashD}`, textAlign: "center" }}>
                <div style={{ fontFamily: font.display, fontSize: 28, color: gradeFromScore(avg).color, fontWeight: 800 }}>{avg}</div>
                <div style={{ fontSize: 12, color: B.slateL }}>Average Score</div>
              </div>
              <div style={{ background: B.white, borderRadius: 10, padding: "16px 24px", border: `1px solid ${B.ashD}`, textAlign: "center" }}>
                <div style={{ fontFamily: font.display, fontSize: 28, color: B.slate, fontWeight: 800 }}>{history.length}</div>
                <div style={{ fontSize: 12, color: B.slateL }}>Attempts</div>
              </div>
              <div style={{ background: B.white, borderRadius: 10, padding: "16px 24px", border: `1px solid ${B.ashD}`, textAlign: "center" }}>
                <div style={{ fontFamily: font.display, fontSize: 28, color: B.slate, fontWeight: 800 }}>{new Set(history.map(h => h.scenarioId)).size}</div>
                <div style={{ fontSize: 12, color: B.slateL }}>Unique Scenarios</div>
              </div>
            </div>
          )}

          {history.length === 0 ? (
            <div style={{ background: B.white, borderRadius: 12, border: `1px solid ${B.ashD}`, padding: 48, textAlign: "center" }}>
              <div style={{ fontSize: 40, marginBottom: 16 }}>📭</div>
              <div style={{ fontFamily: font.display, fontSize: 18, color: B.slate, marginBottom: 8 }}>NO SUBMISSIONS YET</div>
              <p style={{ color: B.slateL, marginBottom: 20 }}>Complete a scenario to see your results here.</p>
              <button onClick={() => setView("home")} style={{ background: B.lava, color: B.white, border: "none", borderRadius: 8, padding: "10px 24px", fontFamily: font.body, fontSize: 14, fontWeight: 600, cursor: "pointer" }}>
                Start a Scenario
              </button>
            </div>
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
              {history.map(h => {
                const g = gradeFromScore(h.total);
                return (
                  <div key={h.id} style={{ background: B.white, borderRadius: 12, border: `1px solid ${B.ashD}`, padding: 24, display: "flex", gap: 20, alignItems: "center", flexWrap: "wrap" }}>
                    <div style={{ width: 56, height: 56, borderRadius: "50%", background: g.bg, border: `3px solid ${g.color}`, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: font.display, fontSize: 22, fontWeight: 800, color: g.color, flexShrink: 0 }}>
                      {g.letter}
                    </div>
                    <div style={{ flex: 1, minWidth: 200 }}>
                      <div style={{ fontWeight: 600, color: B.slate, fontSize: 15, marginBottom: 4 }}>{h.scenarioTitle}</div>
                      <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                        <Badge label={h.tag} color={B.white} bg={tagColor(h.tag)} />
                        <span style={{ fontSize: 12, color: B.slateL }}>{h.timestamp}</span>
                      </div>
                    </div>
                    <div style={{ textAlign: "right" }}>
                      <div style={{ fontFamily: font.display, fontSize: 24, fontWeight: 800, color: g.color }}>{h.total}</div>
                      <div style={{ fontSize: 11, color: B.slateL }}>/ 100</div>
                    </div>
                    <div style={{ display: "grid", gridTemplateColumns: "repeat(5, 1fr)", gap: 8, width: "100%", marginTop: 8, borderTop: `1px solid ${B.ashD}`, paddingTop: 12 }}>
                      {SCORE_CATS.map(c => (
                        <div key={c.key} style={{ textAlign: "center" }}>
                          <div style={{ fontSize: 10, color: B.slateL, marginBottom: 3 }}>{c.label}</div>
                          <div style={{ fontSize: 14, fontWeight: 700, color: gradeFromScore(h.scores[c.key] * 5).color }}>{h.scores[c.key]}<span style={{ fontSize: 10, color: B.slateL }}>/20</span></div>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    );
  }

  return null;
}
